import{_ as d,o as e,c as o,ag as r}from"./chunks/framework.OsDJF_Ea.js";const h=JSON.parse('{"title":"All Rules Reference","description":"","frontmatter":{},"headers":[],"relativePath":"rules.md","filePath":"rules.md"}'),a={name:"rules.md"};function c(i,t,n,l,s,_){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="all-rules-reference" tabindex="-1">All Rules Reference <a class="header-anchor" href="#all-rules-reference" aria-label="Permalink to &quot;All Rules Reference&quot;">​</a></h1><p>This page lists every rule CatalystOps checks. For context and fix examples, see <a href="/docs/local-analysis.html">Local Analysis</a> and <a href="/docs/plan-analysis.html">Plan Analysis</a>.</p><h2 id="static-code-rules" tabindex="-1">Static Code Rules <a class="header-anchor" href="#static-code-rules" aria-label="Permalink to &quot;Static Code Rules&quot;">​</a></h2><h3 id="critical" tabindex="-1">Critical <a class="header-anchor" href="#critical" aria-label="Permalink to &quot;Critical&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rule ID</th><th>Name</th><th>Description</th></tr></thead><tbody><tr><td><code>CODE_COLLECT_001</code></td><td>collect() Usage</td><td>Brings all data to the driver — OOM risk</td></tr><tr><td><code>CODE_ITER_COLLECT_001</code></td><td>for-loop over collect()</td><td>Row-by-row iteration on the driver</td></tr><tr><td><code>CODE_CROSSJOIN_001</code></td><td>Cross Join</td><td>Cartesian product — exponential data growth</td></tr><tr><td><code>CODE_SQL_INJECT_001</code></td><td>SQL Injection</td><td>f-string in spark.sql()</td></tr><tr><td><code>CODE_KAFKA_COMMIT_001</code></td><td>Kafka Auto-Commit</td><td>Can cause data loss or duplication</td></tr><tr><td><code>CODE_DLT_CDC_ORDER_001</code></td><td>DLT CDC Clause Order</td><td>APPLY AS DELETE WHEN in wrong order</td></tr></tbody></table><h3 id="warning" tabindex="-1">Warning <a class="header-anchor" href="#warning" aria-label="Permalink to &quot;Warning&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rule ID</th><th>Name</th><th>Description</th></tr></thead><tbody><tr><td><code>CODE_PANDAS_001</code></td><td>toPandas()</td><td>Brings all data to driver</td></tr><tr><td><code>CODE_COUNT_001</code></td><td>count() &gt; 0</td><td>Use isEmpty() instead</td></tr><tr><td><code>CODE_COALESCE_001</code></td><td>coalesce(1)</td><td>Funnels all data to one partition</td></tr><tr><td><code>CODE_ORDERBY_001</code></td><td>Global orderBy</td><td>Full shuffle</td></tr><tr><td><code>CODE_REPARTITION_001</code></td><td>repartition before write</td><td>Use coalesce()</td></tr><tr><td><code>CODE_WINDOW_001</code></td><td>Window without partitionBy</td><td>Global window</td></tr><tr><td><code>CODE_WITHCOLUMN_LOOP_001</code></td><td>withColumn in loop</td><td>New plan node per iteration</td></tr><tr><td><code>CODE_REPEATED_ACTIONS_001</code></td><td>Repeated actions without cache</td><td>Recomputes the DataFrame</td></tr><tr><td><code>CODE_UDF_FILTER_001</code></td><td>UDF in filter()</td><td>Blocks predicate pushdown</td></tr><tr><td><code>CODE_STREAMING_TRIGGER_001</code></td><td>No .trigger()</td><td>Continuous micro-batches</td></tr><tr><td><code>CODE_STREAMING_WATERMARK_001</code></td><td>Streaming groupBy without watermark</td><td>Unbounded state</td></tr><tr><td><code>CODE_STREAMING_INNER_JOIN_001</code></td><td>Streaming inner join</td><td>Silently drops late events</td></tr><tr><td><code>CODE_DYNAMIC_ALLOC_001</code></td><td>Dynamic allocation on streaming</td><td>Cluster instability</td></tr><tr><td><code>CODE_AUTOLOADER_RATE_001</code></td><td>Auto Loader without rate limit</td><td>Unbounded ingestion</td></tr><tr><td><code>CODE_CHECKPOINT_DBFS_001</code></td><td>Checkpoint on DBFS</td><td>Use cloud storage</td></tr><tr><td><code>CODE_OPTIMIZE_MERGE_001</code></td><td>OPTIMIZE after every MERGE</td><td>Latency spikes</td></tr><tr><td><code>CODE_DROP_CREATE_001</code></td><td>DROP + CREATE TABLE</td><td>Non-atomic, use CREATE OR REPLACE</td></tr><tr><td><code>CODE_FLOAT_FINANCIAL_001</code></td><td>FLOAT for financial data</td><td>Use DECIMAL</td></tr></tbody></table><h3 id="info" tabindex="-1">Info <a class="header-anchor" href="#info" aria-label="Permalink to &quot;Info&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rule ID</th><th>Name</th><th>Description</th></tr></thead><tbody><tr><td><code>CODE_UDF_001</code></td><td>UDF Usage</td><td>Prevents query plan optimization</td></tr><tr><td><code>CODE_SCHEMA_001</code></td><td>Schema Inference</td><td>Extra data pass</td></tr><tr><td><code>CODE_SELECT_STAR_001</code></td><td>SELECT *</td><td>Reads unnecessary columns</td></tr><tr><td><code>CODE_WRITE_MODE_001</code></td><td>Missing write mode</td><td>Defaults to error</td></tr><tr><td><code>CODE_REPRO_001</code></td><td>Repeated source without cache</td><td>Multiple scans</td></tr><tr><td><code>CODE_ROCKSDB_001</code></td><td>Stateful streaming without RocksDB</td><td>State store performance</td></tr><tr><td><code>CODE_UNNAMED_QUERY_001</code></td><td>Unnamed streaming query</td><td>Hard to monitor</td></tr><tr><td><code>CODE_MERGE_DV_001</code></td><td>MERGE without Deletion Vectors</td><td>Performance on large tables</td></tr><tr><td><code>CODE_MERGE_RLC_001</code></td><td>MERGE without Row-Level Concurrency</td><td>Concurrency issues</td></tr><tr><td><code>CODE_ZORDER_001</code></td><td>ZORDER</td><td>Deprecated; use Liquid Clustering</td></tr><tr><td><code>CODE_ANALYZE_001</code></td><td>Missing ANALYZE TABLE</td><td>Stale statistics</td></tr><tr><td><code>CODE_DLT_PARTITION_001</code></td><td>DLT PARTITIONED BY</td><td>Use Liquid Clustering</td></tr><tr><td><code>CODE_READ_FILES_SCHEMA_001</code></td><td>read_files() without schemaHints</td><td>Schema inference per run</td></tr></tbody></table><h2 id="plan-level-detectors" tabindex="-1">Plan-Level Detectors <a class="header-anchor" href="#plan-level-detectors" aria-label="Permalink to &quot;Plan-Level Detectors&quot;">​</a></h2><p>These run after a dry run or job run analysis and require an actual Catalyst execution plan:</p><table tabindex="0"><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td><code>BroadcastHashJoin</code> (missing)</td><td>Sort-merge join where broadcast would be faster</td></tr><tr><td><code>CartesianProduct</code></td><td>Cartesian join in the physical plan</td></tr><tr><td><code>ShuffleExchange</code></td><td>Unnecessary shuffle</td></tr><tr><td><code>SinglePartitionBottleneck</code></td><td>Exchange SinglePartition — all data on one executor</td></tr><tr><td><code>SortAggregate</code></td><td>Sort-based aggregation (prefer hash-based)</td></tr><tr><td><code>GlobalWindow</code> / <code>RunningWindowFunction</code></td><td>Global window, Photon-aware</td></tr><tr><td><code>RepeatedTableScan</code></td><td>Same table scanned multiple times</td></tr><tr><td><code>MissingPartitionFilter</code></td><td>Partition filters empty — full table scan</td></tr><tr><td><code>MissingTableStatistics</code></td><td>Table has no statistics</td></tr><tr><td><code>CacheSpill</code></td><td>Cached data spilling to disk</td></tr><tr><td><code>TooFewPartitions</code></td><td>Low parallelism for data size</td></tr><tr><td><code>CrossJoin</code></td><td>Cartesian join (also caught by local analysis)</td></tr><tr><td><code>UnionSchemaMismatch</code></td><td>Column order mismatch (also caught by local analysis)</td></tr></tbody></table>',12)])])}const u=d(a,[["render",c]]);export{h as __pageData,u as default};
